/**
 * Webhook notification adapter — delivers notifications via HTTP POST.
 *
 * Features:
 * - Formats notification payloads as JSON
 * - POSTs to a configured webhook URL
 * - Pluggable transport: supports swappable HTTP transports (fetch, in-memory for tests)
 *
 * Architecture: Implements NotificationAdapter interface. Registered with
 * NotificationService via registerAdapter(). All webhook delivery flows through
 * the EventBus → NotificationService → WebhookAdapter pipeline.
 */

import type { NotificationPayload } from '../models/notification.js';
import type { NotificationAdapter } from './notification.adapter.js';
import { Logger } from '../utils/logger.js';

/**
 * The JSON body sent to webhook endpoints.
 */
export interface WebhookPayload {
  id: string;
  type: string;
  channel: string;
  recipient: string;
  subject: string;
  body: string;
  metadata: Record<string, unknown>;
  createdAt: string;
}

/**
 * Pluggable transport interface for HTTP delivery.
 * Implement this for fetch, axios, or testing.
 */
export interface WebhookTransport {
  post(url: string, body: WebhookPayload): Promise<void>;
}

/**
 * In-memory transport that captures webhook deliveries for testing.
 */
export class InMemoryWebhookTransport implements WebhookTransport {
  private deliveries: Array<{ url: string; body: WebhookPayload }> = [];

  async post(url: string, body: WebhookPayload): Promise<void> {
    this.deliveries.push({ url, body });
  }

  getDeliveries(): Array<{ url: string; body: WebhookPayload }> {
    return [...this.deliveries];
  }

  clear(): void {
    this.deliveries = [];
  }
}

export interface WebhookConfig {
  /** The webhook endpoint URL */
  url: string;
  /** HTTP transport (defaults to InMemoryWebhookTransport) */
  transport?: WebhookTransport;
}

const URL_REGEX = /^https?:\/\/.+/;

/**
 * Validate a webhook URL.
 * @throws Error if the URL is not a valid HTTP/HTTPS URL
 */
export function validateWebhookUrl(url: string): string {
  const trimmed = url.trim();
  if (!URL_REGEX.test(trimmed)) {
    throw new Error(`Invalid webhook URL: ${url}`);
  }
  return trimmed;
}

/**
 * Format a NotificationPayload into a WebhookPayload for JSON delivery.
 */
export function formatWebhookPayload(payload: NotificationPayload): WebhookPayload {
  return {
    id: payload.id,
    type: payload.type,
    channel: payload.channel,
    recipient: payload.recipient,
    subject: payload.subject,
    body: payload.body,
    metadata: payload.metadata,
    createdAt: payload.createdAt.toISOString(),
  };
}

export class WebhookAdapter implements NotificationAdapter {
  readonly channel = 'webhook' as const;
  private logger = new Logger('WebhookAdapter');
  private transport: WebhookTransport;
  private url: string;

  constructor(private config: WebhookConfig) {
    this.url = validateWebhookUrl(config.url);
    this.transport = config.transport ?? new InMemoryWebhookTransport();
  }

  /**
   * Send a notification via webhook POST.
   * Formats the payload as JSON and POSTs it to the configured URL.
   * @param payload - The notification to deliver
   * @throws Error if the transport fails
   */
  async send(payload: NotificationPayload): Promise<void> {
    const webhookPayload = formatWebhookPayload(payload);
    await this.transport.post(this.url, webhookPayload);
    this.logger.info(`Webhook delivered to ${this.url}: ${payload.id}`);
  }

  /**
   * Get the transport (for testing access to InMemoryWebhookTransport).
   */
  getTransport(): WebhookTransport {
    return this.transport;
  }

  /**
   * Convenience: get delivered webhooks when using InMemoryWebhookTransport.
   * @throws Error if transport is not InMemoryWebhookTransport
   */
  getDeliveries(): Array<{ url: string; body: WebhookPayload }> {
    if (this.transport instanceof InMemoryWebhookTransport) {
      return this.transport.getDeliveries();
    }
    throw new Error('getDeliveries() is only available with InMemoryWebhookTransport');
  }

  /**
   * Convenience: clear delivered webhooks when using InMemoryWebhookTransport.
   */
  clearDeliveries(): void {
    if (this.transport instanceof InMemoryWebhookTransport) {
      this.transport.clear();
    }
  }
}

