import { describe, it, expect, beforeEach } from 'vitest';
import {
  WebhookAdapter,
  InMemoryWebhookTransport,
  validateWebhookUrl,
  formatWebhookPayload,
} from '../../src/adapters/webhook.adapter.js';
import type { WebhookTransport, WebhookPayload } from '../../src/adapters/webhook.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides: Partial<NotificationPayload> = {}): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order_confirmation',
    channel: 'webhook',
    recipient: 'https://example.com/webhook',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    metadata: {
      orderId: 'order-1',
      userId: 'user-1',
      items: [{ name: 'Widget', quantity: 2, unitPrice: 10 }],
      total: 20,
    },
    createdAt: new Date('2026-01-15'),
    ...overrides,
  };
}

describe('validateWebhookUrl', () => {
  it('should accept valid HTTP URLs', () => {
    expect(validateWebhookUrl('http://example.com/hook')).toBe('http://example.com/hook');
  });

  it('should accept valid HTTPS URLs', () => {
    expect(validateWebhookUrl('https://example.com/hook')).toBe('https://example.com/hook');
  });

  it('should trim whitespace', () => {
    expect(validateWebhookUrl('  https://example.com/hook  ')).toBe('https://example.com/hook');
  });

  it('should reject non-HTTP URLs', () => {
    expect(() => validateWebhookUrl('ftp://example.com')).toThrow('Invalid webhook URL');
  });

  it('should reject empty strings', () => {
    expect(() => validateWebhookUrl('')).toThrow('Invalid webhook URL');
  });

  it('should reject strings without protocol', () => {
    expect(() => validateWebhookUrl('example.com/hook')).toThrow('Invalid webhook URL');
  });
});

describe('formatWebhookPayload', () => {
  it('should convert NotificationPayload to WebhookPayload', () => {
    const payload = makePayload();
    const result = formatWebhookPayload(payload);

    expect(result).toEqual({
      id: 'notif-0001',
      type: 'order_confirmation',
      channel: 'webhook',
      recipient: 'https://example.com/webhook',
      subject: 'Order Confirmation: order-1',
      body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
      metadata: {
        orderId: 'order-1',
        userId: 'user-1',
        items: [{ name: 'Widget', quantity: 2, unitPrice: 10 }],
        total: 20,
      },
      createdAt: '2026-01-15T00:00:00.000Z',
    });
  });

  it('should serialize createdAt as ISO string', () => {
    const date = new Date('2026-06-15T12:30:00Z');
    const payload = makePayload({ createdAt: date });
    const result = formatWebhookPayload(payload);
    expect(result.createdAt).toBe('2026-06-15T12:30:00.000Z');
  });
});

describe('InMemoryWebhookTransport', () => {
  let transport: InMemoryWebhookTransport;

  beforeEach(() => {
    transport = new InMemoryWebhookTransport();
  });

  it('should capture deliveries', async () => {
    const body: WebhookPayload = formatWebhookPayload(makePayload());
    await transport.post('https://example.com/hook', body);

    const deliveries = transport.getDeliveries();
    expect(deliveries).toHaveLength(1);
    expect(deliveries[0].url).toBe('https://example.com/hook');
    expect(deliveries[0].body.id).toBe('notif-0001');
  });

  it('should return a copy of deliveries', async () => {
    const body: WebhookPayload = formatWebhookPayload(makePayload());
    await transport.post('https://example.com/hook', body);

    const d1 = transport.getDeliveries();
    const d2 = transport.getDeliveries();
    expect(d1).not.toBe(d2);
    expect(d1).toEqual(d2);
  });

  it('should clear deliveries', async () => {
    const body: WebhookPayload = formatWebhookPayload(makePayload());
    await transport.post('https://example.com/hook', body);
    transport.clear();
    expect(transport.getDeliveries()).toHaveLength(0);
  });
});

describe('WebhookAdapter', () => {
  let adapter: WebhookAdapter;
  let transport: InMemoryWebhookTransport;

  beforeEach(() => {
    transport = new InMemoryWebhookTransport();
    adapter = new WebhookAdapter({
      url: 'https://example.com/webhook',
      transport,
    });
  });

  it('should have channel set to webhook', () => {
    expect(adapter.channel).toBe('webhook');
  });

  it('should send notification payload as JSON POST', async () => {
    const payload = makePayload();
    await adapter.send(payload);

    const deliveries = transport.getDeliveries();
    expect(deliveries).toHaveLength(1);
    expect(deliveries[0].url).toBe('https://example.com/webhook');
    expect(deliveries[0].body.id).toBe('notif-0001');
    expect(deliveries[0].body.type).toBe('order_confirmation');
    expect(deliveries[0].body.subject).toBe('Order Confirmation: order-1');
  });

  it('should include all metadata in the webhook body', async () => {
    const payload = makePayload();
    await adapter.send(payload);

    const deliveries = transport.getDeliveries();
    expect(deliveries[0].body.metadata).toEqual({
      orderId: 'order-1',
      userId: 'user-1',
      items: [{ name: 'Widget', quantity: 2, unitPrice: 10 }],
      total: 20,
    });
  });

  it('should serialize createdAt as ISO string', async () => {
    const payload = makePayload({ createdAt: new Date('2026-03-01T10:00:00Z') });
    await adapter.send(payload);

    const deliveries = transport.getDeliveries();
    expect(deliveries[0].body.createdAt).toBe('2026-03-01T10:00:00.000Z');
  });

  it('should handle all notification types', async () => {
    const types = ['order_confirmation', 'order_status_update', 'welcome', 'account_updated'] as const;

    for (const type of types) {
      await adapter.send(makePayload({ type }));
    }

    const deliveries = transport.getDeliveries();
    expect(deliveries).toHaveLength(4);
    expect(deliveries.map((d) => d.body.type)).toEqual([...types]);
  });

  it('should throw on invalid webhook URL in constructor', () => {
    expect(
      () => new WebhookAdapter({ url: 'not-a-url', transport }),
    ).toThrow('Invalid webhook URL');
  });

  it('should propagate transport errors', async () => {
    const failingTransport: WebhookTransport = {
      async post(): Promise<void> {
        throw new Error('Connection refused');
      },
    };

    const failAdapter = new WebhookAdapter({
      url: 'https://example.com/webhook',
      transport: failingTransport,
    });

    await expect(failAdapter.send(makePayload())).rejects.toThrow('Connection refused');
  });

  it('should use InMemoryWebhookTransport by default', () => {
    const defaultAdapter = new WebhookAdapter({ url: 'https://example.com/hook' });
    expect(defaultAdapter.getTransport()).toBeInstanceOf(InMemoryWebhookTransport);
  });

  it('should expose getDeliveries convenience method', async () => {
    await adapter.send(makePayload());
    const deliveries = adapter.getDeliveries();
    expect(deliveries).toHaveLength(1);
  });

  it('should throw getDeliveries when not using InMemoryWebhookTransport', () => {
    const customTransport: WebhookTransport = {
      async post(): Promise<void> {},
    };
    const customAdapter = new WebhookAdapter({
      url: 'https://example.com/hook',
      transport: customTransport,
    });

    expect(() => customAdapter.getDeliveries()).toThrow(
      'getDeliveries() is only available with InMemoryWebhookTransport',
    );
  });

  it('should clear deliveries via convenience method', async () => {
    await adapter.send(makePayload());
    adapter.clearDeliveries();
    expect(adapter.getDeliveries()).toHaveLength(0);
  });
});

